import React from 'react';

const TestImagen = () => {
  const imagenUrl = "https://drive.google.com/uc?export=view&id=1zsV4NBo1dKAtXtUFhYnWbHKZGT5tPaFm"; // Asegúrate de que esta URL sea correcta

  return (
    <div style={{ width: "100%", height: "500px", display: "flex", justifyContent: "center", alignItems: "center" }}>
      <img
        src={imagenUrl}
        alt="Imagen de prueba"
        style={{
          width: '80%',   // Ajusta el tamaño según sea necesario
          height: 'auto', // Mantiene la proporción
          objectFit: 'contain', // Mantiene la proporción sin distorsionar
        }}
      />
    </div>
  );
};

export default TestImagen;
